import math

def process_deployment_config(config):
    """
    Processes a deployment configuration dictionary.
    """
    if not config:
        return {"status": "error", "message": "Empty config"}

    try:
        env = config.get("environment", "development")
        replicas = config.get("replicas", 1)

        if not isinstance(replicas, int) or replicas <= 0:
            return {"status": "error", "message": "Invalid replicas"}

        if env == "production":
            if replicas < 3:
                return {"status": "error", "message": "Production requires at least 3 replicas"}
            scaling_factor = 1.5
        elif env == "staging":
            scaling_factor = 1.2
        else:
            scaling_factor = 1.0

        # Simulate some math logic
        load_calc = math.sqrt(replicas) * scaling_factor

        return {
            "status": "success",
            "env": env,
            "load_factor": load_calc,
            "ready": True
        }

    except Exception as e:
        return {"status": "error", "message": str(e)}

def validate_resource_limits(limits):
    if "cpu" in limits and limits["cpu"] > 100:
        return False
    if "memory" in limits and limits["memory"] < 128:
